mapper.select:
SELECT id
FROM iot_device_command_record
WHERE create_time < #{beforeTime}
ORDER BY create_time ASC
LIMIT #{limit}

mapper.delete:
DELETE FROM iot_device_command_record_history
WHERE backup_time < #{beforeTime}
LIMIT #{limit}

mapper.select:
SELECT id
FROM iot_device_operation_log
WHERE operation_time < #{beforeTime}
ORDER BY operation_time ASC
LIMIT #{limit}

mapper.delete:
DELETE FROM iot_device_operation_log_history
WHERE backup_time < #{beforeTime}
LIMIT #{limit}

mapper.select:
